/* Required a JavaScript scroll listener */
window.addEventListener('scroll', () => {
  const nav = document.querySelector('.nav');
  if (window.scrollY > 0) {
    nav.classList.add('is-stuck');
  } else {
    nav.classList.remove('is-stuck');
  }
});
/* .is-stuck { position: fixed; top: 0; } */

