.scroll-container {
  height: 260px;
  overflow-y: auto;
  background: #0f172a;
  border-radius: 10px;
  border: 1px solid #334155;
}

.sticky-nav {
  background: #7c3aed;
  color: white;
  padding: 0.75rem 1rem;
  font-weight: 600;
  font-size: 0.9rem;
  /* Make this stick to the top while scrolling */
}

.content {
  padding: 1rem;
  color: #94a3b8;
  font-size: 0.875rem;
  line-height: 1.7;
}

.content p {
  margin: 0 0 0.75rem;
}
